import { useState, useEffect } from "react";

export default function ClientManagement() {
  const [clients, setClients] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    address: "",
    project: "",
    floor: "",
    room: "",
    amount_paid: ""
  });

  // Fetch clients from backend
  const fetchClients = async () => {
    try {
      const res = await fetch("http://localhost:5000/clients");
      const data = await res.json();
      setClients(data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchClients();
  }, []);

  // Handle input change
  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name === "phone") {
      const numeric = value.replace(/\D/g, "");
      if (numeric.length <= 10) setFormData({ ...formData, phone: numeric });
      return;
    }
    setFormData({ ...formData, [name]: value });
  };

  // Generate rooms for floor
  const generateRooms = (floor) => {
    if (!floor) return [];
    let rooms = [];
    for (let i = 1; i <= 10; i++) rooms.push(`${floor}${i.toString().padStart(2, "0")}`);
    // mark booked rooms
    const bookedRooms = clients
      .filter(c => c.floor == floor)
      .map(c => c.room.toString());
    return rooms.map(r => bookedRooms.includes(r) ? `${r} (Booked)` : r);
  };

  // Submit form
  const handleSubmit = async () => {
    if (!formData.name) return alert("Enter name");
    if (formData.phone.length !== 10) return alert("Phone must be 10 digits");

    try {
      const res = await fetch(editId ? `http://localhost:5000/clients/${editId}` : "http://localhost:5000/clients", {
        method: editId ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...formData, room: formData.room.replace(" (Booked)", "") })
      });

      const data = await res.json();

      if (res.status === 400 && data.error) return alert(data.error);

      fetchClients();
      setShowForm(false);
      setEditId(null);
      setFormData({ name: "", phone: "", address: "", project: "", floor: "", room: "", amount_paid: "" });
    } catch (err) {
      console.log(err);
      alert("Failed to save client");
    }
  };

  const handleEdit = (c) => {
    setFormData({
      name: c.name,
      phone: c.phone,
      address: c.address,
      project: c.project,
      floor: c.floor,
      room: c.room,
      amount_paid: c.amount_paid
    });
    setEditId(c.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    await fetch(`http://localhost:5000/clients/${id}`, { method: "DELETE" });
    fetchClients();
  };

  return (
    <div className="p-8">
      <h1 className="text-2xl mb-4">Client Management</h1>

      <button onClick={() => setShowForm(true)}>+ Add Client</button>

      {showForm && (
        <div className="bg-gray-100 p-4 mt-4 rounded">
          <input name="name" value={formData.name} onChange={handleChange} placeholder="Name" />
          <input name="phone" value={formData.phone} onChange={handleChange} placeholder="Phone" />
          <input name="address" value={formData.address} onChange={handleChange} placeholder="Address" />
          <input name="project" value={formData.project} onChange={handleChange} placeholder="Project" />
          <input name="floor" value={formData.floor} onChange={handleChange} placeholder="Floor" />
          <select name="room" value={formData.room} onChange={handleChange}>
            <option value="">Select Room</option>
            {generateRooms(formData.floor).map(r => <option key={r} value={r}>{r}</option>)}
          </select>
          <input name="amount_paid" value={formData.amount_paid} onChange={handleChange} placeholder="Amount Paid" type="number" />
          <button onClick={handleSubmit}>{editId ? "Update" : "Save"}</button>
          <button onClick={() => setShowForm(false)}>Cancel</button>
        </div>
      )}

      <table className="mt-4 border">
        <thead>
          <tr>
            <th>Name</th><th>Phone</th><th>Project</th><th>Floor</th><th>Room</th><th>Paid</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {clients.map(c => (
            <tr key={c.id}>
              <td>{c.name}</td>
              <td>{c.phone}</td>
              <td>{c.project}</td>
              <td>{c.floor}</td>
              <td>{c.room}</td>
              <td>{c.amount_paid}</td>
              <td>
                <button onClick={() => handleEdit(c)}>Edit</button>
                <button onClick={() => handleDelete(c.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
